      "num_retained_start_tokens_in_cache": 128,
      "num_retained_recent_tokens_in_cache": 1920,
      "num_last_dense_tokens_in_prefill": 100,
      "xattention_block_size": 64,
      "xattention_stride": 8,
      "xattention_threshold": 0.80
    }
  },
  "calibration": {
    "dense_tps_4k": ...,
