    "source": "p5_task4_3_nat_sweep_matrix.json",
    "nat": 3,
    "entries": [
      {
        "band": 4096,
        "combined_tps": { "mean": ... },
        "ttft_ms": { "mean": ... },
        "acceptance_rate_aggregate": ...,
        "peak_rss_mb": ...
      }
      // ... 5 entries (one per band)
    ]
  },
  "results": [
    {
      "band": 4096,
      "sparse_mode": "TRISHAPE",
      "status": "completed | OOM_SKIPPED | INSUFFICIENT_DATA | API_NOT_AVAILABLE",
      "warmup_runs": 2,
      "measured_runs": [ ... per-run 7-field records ... ],
      "summary": {
        "combined_tps": { "mean": ..., "stddev": ..., "p50": ..., "p95": ... },
        "ttft_ms": { "mean": ..., "stddev": ... },
        "draft_forward_ms_per_step": { "mean": ... },
        "tokens_drafted_total": ...,
        "tokens_accepted_total": ...,
        "acceptance_rate_aggregate": ...,
        "acceptance_rate_by_step": [step_1, step_2, step_3],
        "peak_rss_mb": ...
      },
      "delta_vs_baseline": {
        "ttft_delta_pct": ...,
        "tps_ratio": ...,
        "ar_delta": ...,
        "rss_delta_mb": ...
      }
    }
    // ... 10 entries total (2 sparse modes × 5 bands)
  ],
  "analysis": {
    "ttft_improvement_bands": {
      "TRISHAPE": { "4096": ..., "8192": ..., "12288": ..., "16384": ..., "20480": ... },
      "XATTENTION": { ... }
    },
    "tps_compatibility": {
