      "XATTENTION": { ... }
    },
    "ar_collapse_shift": {
      "baseline_collapse_band": 16384,
      "trishape_ar_at_16k": ...,
      "xattention_ar_at_16k": ...,
      "collapse_boundary_shifted": true | false
    },
    "rss_deltas": { ... per-band rss comparison ... },
    "mode_comparison": {
      "overall_winner": "TRISHAPE | XATTENTION | EQUIVALENT",
      "per_band_winners": { ... }
    }
