  "quality_gate": {
    "G-01": "PASS|FAIL",
    "G-02": "PASS|FAIL",
    "G-03": "PASS|FAIL|SPARSE_CANDIDATE|STRONG_SPARSE_CANDIDATE",
    "G-04": "PASS|FAIL notes...",
